#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen::literals;

  // Connect to the database
  auto result = sqlgen::sqlite::connect("test_db.sqlite")
      // Start transaction
      | sqlgen::begin_transaction
      // Read sender's account to check balance
      | [](auto conn) {
          return (sqlgen::read<Account> | sqlgen::where("account_id"_c == from_account_id))(conn);
      }
      // Check if sufficient funds exist
      | [](auto sender_result) {
          if (!sender_result) {
              return sqlgen::rollback;
          }
          auto sender = sender_result.value();
          if (sender.balance < amount) {
              return sqlgen::rollback;
          }
          return sender;
      }
      // Update sender's balance
      | [](auto sender) {
          return (sqlgen::update<Account>("balance"_c = "balance"_c - amount) 
                  | sqlgen::where("account_id"_c == from_account_id))(sender);
      }
      // Update receiver's balance
      | [](auto conn) {
          return (sqlgen::update<Account>("balance"_c = "balance"_c + amount) 
                  | sqlgen::where("account_id"_c == to_account_id))(conn);
      }
      // Commit transaction
      | sqlgen::commit;

  // Return true if successful, false if any step failed
  return result ? true : false;
}

}  // namespace transaction_transfer_funds
