 * Returns: std::vector<FriendConnection>.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  using namespace sqlgen::literals;

  // 1. Create database connection
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // 2. Drop tables if they exist
  (sqlgen::drop<User> | sqlgen::if_exists)(conn);
  (sqlgen::drop<Friendship> | sqlgen::if_exists)(conn);

  // 3. Create tables
  sqlgen::create_table<User>(conn);
  sqlgen::create_table<Friendship>(conn);

  // 4. Insert data
  sqlgen::write(conn, users);
  sqlgen::write(conn, friendships);

  // 5. Query 1: Mutual friends using SELF-JOIN
  auto mutual_friends_query = sqlgen::select_from<User, "u1">(
      "username"_t1 | sqlgen::as<"user1_name">,
      "username"_t2 | sqlgen::as<"user2_name">
  )
  .inner_join<Friendship, "f1">("user_id"_t1 == "user_id1"_t1)
  .inner_join<Friendship, "f2">("user_id2"_t1 == "user_id1"_t2)
  .inner_join<User, "u2">("user_id2"_t2 == "user_id"_t2)
  .where("user_id"_t1 < "user_id"_t2)
  .group_by("user_id"_t1, "user_id"_t2)
  .having(sqlgen::count("user_id2"_t1) > 0)
  .to<std::vector<FriendConnection>>;

  // 6. Execute the query and return results
  auto result = mutual_friends_query(conn);
  if (!result) {
    throw std::runtime_error("Query failed: " + result.error().what());
  }

  return result.value();
}

}  // namespace analyze_social_network
