namespace mathematical_operations_analysis {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  double price;
  int quantity;
  double discount_rate;
};

struct MathAnalysis {
  int product_id;
  std::string name;
  double abs_price;
  double ceil_price;
  double floor_price;
  double rounded_price;
  double exp_discount;
  double ln_price;
  double log2_quantity;
  double sin_discount;
