```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace analyze_department_employees {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string department_name;
  std::string location;
};

struct Employee {
  sqlgen::PrimaryKey<int> employee_id;
  int department_id;
  std::string first_name;
  std::string last_name;
  double salary;
};

struct JoinResult {
  std::optional<std::string> department_name;
  std::optional<std::string> first_name;
  std::optional<std::string> last_name;
  std::optional<double> salary;
};

struct JoinAnalysis {
  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating temporary SQL tables, inserting the provided rows, and executing a
 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen::literals;

  // 1. Connect to an in-memory database
  auto conn = sqlgen::sqlite::connect(":memory:");

  // 2. Create the Department and Employee tables
  conn | sqlgen::create_table<Department> | sqlgen::if_not_exists;
  conn | sqlgen::create_table<Employee> | sqlgen::if_not_exists;

  // 3. Insert the provided department and employee data
  conn.insert(depts.begin(), depts.end());
  conn.insert(emps.begin(), emps.end());

  // 4. Perform the four required joins using sqlgen functions and operators

  // INNER JOIN: Employees with assigned departments
  auto inner_query = sqlgen::select_from<Department, "d">(
      "department_name"_t1,
      "first_name"_t2,
      "last_name"_t2,
      "salary"_t2
  ) | sqlgen::inner_join<Employee, "e">("department_id"_t1 == "department_id"_t2)
    | sqlgen::to<std::vector<JoinResult>>;

  // LEFT JOIN: Include all employees (even without departments)
  auto left_query = sqlgen::select_from<Employee, "e">(
      "department_name"_t1,
      "first_name"_t2,
      "last_name"_t2,
      "salary"_t2
  ) | sqlgen::left_join<Department, "d">("department_id"_t2 == "department_id"_t1)
    | sqlgen::to<std::vector<JoinResult>>;

  // RIGHT JOIN: Include all departments (even without employees)
  auto right_query = sqlgen::select_from<Department, "d">(
      "department_name"_t1,
      "first_name"_t2,
      "last_name"_t2,
      "salary"_t2
  ) | sqlgen::right_join<Employee, "e">("department_id"_t1 == "department_id"_t2)
    | sqlgen::to<std::vector<JoinResult>>;

  // FULL JOIN: Include all employees and departments
  auto full_query = sqlgen::select_from<Department, "d">(
      "department_name"_t1,
      "first_name"_t2,
      "last_name"_t2,
      "salary"_t2
  ) | sqlgen::full_join<Employee, "e">("department_id"_t1 == "department_id"_t2)
    | sqlgen::to<std::vector<JoinResult>>;

  // 5. Execute the queries and populate the JoinAnalysis structure
  JoinAnalysis analysis;

  // Execute INNER JOIN
  auto inner_result = inner_query(conn);
  if (inner_result) {
    analysis.inner_join_results = std::move(*inner_result);
  }

  // Execute LEFT JOIN
  auto left_result = left_query(conn);
  if (left_result) {
    analysis.left_join_results = std::move(*left_result);
  }

  // Execute RIGHT JOIN
  auto right_result = right_query(conn);
  if (right_result) {
    analysis.right_join_results = std::move(*right_result);
  }

  // Execute FULL JOIN
  auto full_result = full_query(conn);
  if (full_result) {
    analysis.full_join_results = std::move(*full_result);
  }

  return analysis;
}

}  // namespace analyze_department_employees
```

## Key Implementation Details:

1. **Database Connection**: Uses `sqlgen::sqlite::connect(":memory:")` to create an in-memory SQLite database as specified.

2. **Table Creation**: Uses `sqlgen::create_table<T>` with `sqlgen::if_not_exists` to safely create tables only if they don't exist.

3. **Data Insertion**: Uses the connection's `insert()` method to populate the tables with the provided department and employee data.

4. **Join Operations**: Implements all four required join types using sqlgen's fluent API:
   - `sqlgen::inner_join` for INNER JOIN
   - `sqlgen::left_join` for LEFT JOIN  
   - `sqlgen::right_join` for RIGHT JOIN
   - `sqlgen::full_join` for FULL JOIN

5. **Column Selection**: Uses table aliases (`_t1`, `_t2`) and column literals to properly reference columns from both tables in the joins.

6. **Result Mapping**: Uses `sqlgen::to<std::vector<JoinResult>>` to map query results to the `JoinResult` structure with optional fields for proper NULL handling in outer joins.

7. **Error Handling**: Checks the result of each query execution and populates the analysis structure only with valid results.

The implementation follows sqlgen's principles of using a fluent, type-safe API for database operations while meeting all the specified assessment objectives.

